#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /*
     * Control policy:
     * - Boot: heater off
     * - TEMP < 47: turn heater on (HEATING)
     * - TEMP > 52: turn heater off (SAFE_OFF)
     * - 47 <= TEMP < 50: hold previous safe actuator state
     * - 50 <= TEMP <= 52 AND rising temperature: early heater-off (HOLDING), not SAFE_OFF
     * - 50 <= TEMP <= 52 AND not rising: hold previous safe actuator state
     * - Malformed input: turn heater off (SAFE_OFF)
     * - Sensor timeout: turn heater off (SAFE_OFF)
     * - Stale sensor data > 1000ms: turn heater off (SAFE_OFF)
     */

    /* Handle stale sensor data check */
    if (!controller->has_valid_sensor && input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller->timed_out = true;
        output.timed_out = true;
        return output;
    }

    /* Reset state for new valid sensor */
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;

    /* Check if input is malformed or timeout */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || 
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        return output;
    }

    /* Handle temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Apply control policy based on current temperature */
        bool heater_on_now = false;
        int rising_temp = 0;

        if (input.temperature_c < 47) {
            /* Below lower band: turn heater on */
            heater_on_now = true;
        } else if (input.temperature_c > 52) {
            /* Above upper band: turn heater off */
            heater_on_now = false;
        } else {
            /* Inside working band, check for rising temp */
            int prev_temp = controller->last_temperature_c;

            if (prev_temp >= 50 && prev_temp <= 52) {
                /* In upper band - checking if rising */
                rising_temp = input.temperature_c - prev_temp;

                if (rising_temp > 0) {
                    /* Rising temp in upper band: early heater-off as HOLDING */
                    heater_on_now = false;
                } else {
                    /* Not rising, hold previous safe actuator state */
                    heater_on_now = controller->heater_on;
                }
            } else {
                /* Outside working band - turn heater off */
                heater_on_now = false;
            }
        }

        controller_set_safe_off(controller);
    }

    output.heater_on = heater_on_now;
    output.state = CONTROLLER_STATE_HEATING;
    output.state_name = controller_state_name(CONTROLLER_STATE_HEATING);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

