#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

/* Threshold constants for thermal chamber control */
#define CONTROLLER_TEMP_LOW_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 52
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 50
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

/* Input types from the protocol layer */
typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
} controller_input_kind_t;

/* State machine for thermal chamber control */
typedef enum {
    CONTROLLER_STATE_SAFE_OFF = 0,      /* Fail-safe off state */
    CONTROLLER_STATE_HEATING,           /* Actively heating */
    CONTROLLER_STATE_HOLDING,           /* Inside working region, preserving state */
} controller_state_t;

/* Input structure from protocol layer */
typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    uint32_t now_ms;
} controller_input_t;

/* Controller state to be sent to protocol layer */
typedef struct {
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

/* Internal controller state */
typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    uint32_t now_ms;
} controller_input_internal_t;

/* Controller structure */
typedef struct {
    controller_t internal_state;
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_t;

/* Exported functions for public interface */
void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif /* CONTROLLER_H */

