/*
 * Self-verification tests for the thermal chamber hysteresis controller.
 * These are visible tests that run before submitting to the hidden grader.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <assert.h>

#include "components/controller/include/controller.h"

/* Test harness - runs all tests and reports results */
void run_all_tests(void) {
    printf("========================================\n");
    printf("Thermal Chamber Hysteresis Controller\n");
    printf("Self-Verification Tests\n");
    printf("========================================\n\n");

    int passed = 0;
    int failed = 0;

    /* Test 1: Boot leaves heater off */
    printf("Test 1: Boot leaves heater off...\n");
    if (test_boot_leaves_heater_off()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 2: Low temperature drives ACT HEATER ON */
    printf("\nTest 2: Low temperature (35) drives heater on...\n");
    if (test_low_temp_drives_heater_on()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 3: High temperature drives ACT HEATER OFF */
    printf("\nTest 3: High temperature (53) drives heater off...\n");
    if (test_high_temp_drives_heater_off()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 4: Inside band preserves previous safe actuator state */
    printf("\nTest 4: Inside band (48) preserves previous safe state...\n");
    if (test_inside_band_preserves_state()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 5: Near upper band rising temp causes early heater off */
    printf("\nTest 5: Rising temp in upper band (49->50) triggers early off...\n");
    if (test_rising_temp_in_upper_band_triggers_off()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 6: Malformed input forces heater off */
    printf("\nTest 6: Malformed input forces heater off...\n");
    if (test_malformed_input_forces_off()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 7: Stale sensor data > 1000ms forces heater off */
    printf("\nTest 7: Stale sensor data (> 1000ms) forces heater off...\n");
    if (test_stale_sensor_data_forces_off()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 8: Closed-loop keeps chamber at or below 56 C */
    printf("\nTest 8: Closed-loop keeps temperature <= 56C...\n");
    if (test_closed_loop_keeps_temp_below_56()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 9: Controller output structure correctness */
    printf("\nTest 9: Controller output structure is correct...\n");
    if (test_output_structure_correctness()) {
        printf("  PASS\n");
        passed++;
    } else {
        printf("  FAIL\n");
        failed++;
    }

    /* Test 10: State name function correctness */
